    19→namespace AzureMcp.Areas.Storage.Services;
    20→
    21→public class StorageService(ISubscriptionService subscriptionService, ITenantService tenantService, ICacheService cacheService) : BaseAzureService(tenantService), IStorageService
    22→{
    23→    private readonly ISubscriptionService _subscriptionService = subscriptionService ?? throw new ArgumentNullException(nameof(subscriptionService));
    24→    private readonly ICacheService _cacheService = cacheService ?? throw new ArgumentNullException(nameof(cacheService));
    25→    private const string CacheGroup = "storage";
    26→    private const string StorageAccountsCacheKey = "accounts";
    27→    private static readonly TimeSpan s_cacheDuration = TimeSpan.FromHours(1);
    28→
    29→    public async Task<List<string>> GetStorageAccounts(string subscriptionId, string? tenant = null, RetryPolicyOptions? retryPolicy = null)
    30→    {
    31→        ValidateRequiredParameters(subscriptionId);
    32→
    33→        // Create cache key
    34→        var cacheKey = string.IsNullOrEmpty(tenant)
    35→            ? $"{StorageAccountsCacheKey}_{subscriptionId}"
    36→            : $"{StorageAccountsCacheKey}_{subscriptionId}_{tenant}";
    37→
    38→        // Try to get from cache first
    39→        var cachedAccounts = await _cacheService.GetAsync<List<string>>(CacheGroup, cacheKey, s_cacheDuration);
    40→        if (cachedAccounts != null)
    41→        {
    42→            return cachedAccounts;
    43→        }
    44→
    45→        var subscription = await _subscriptionService.GetSubscription(subscriptionId, tenant, retryPolicy);
    46→        var accounts = new List<string>();
    47→        try
    48→        {
    49→            await foreach (var account in subscription.GetStorageAccountsAsync())
    50→            {
    51→                if (account?.Data?.Name != null)
    52→                {
    53→                    accounts.Add(account.Data.Name);
    54→                }
    55→            }
    56→
    57→            // Cache the results
    58→            await _cacheService.SetAsync(CacheGroup, cacheKey, accounts, s_cacheDuration);
    59→        }
    60→        catch (Exception ex)
    61→        {
    62→            throw new Exception($"Error retrieving Storage accounts: {ex.Message}", ex);
    63→        }
    64→
    65→        return accounts;
    66→    }
    67→
    68→    public async Task<List<string>> ListContainers(string accountName, string subscriptionId, string? tenant = null, RetryPolicyOptions? retryPolicy = null)
    69→    {
    70→        ValidateRequiredParameters(accountName, subscriptionId);
    71→
    72→        var blobServiceClient = await CreateBlobServiceClient(accountName, tenant, retryPolicy);
    73→        var containers = new List<string>();
    74→
    75→        try
    76→        {
    77→            await foreach (var container in blobServiceClient.GetBlobContainersAsync())
    78→            {
    79→                containers.Add(container.Name);
    80→            }
    81→        }
    82→        catch (Exception ex)
    83→        {
    84→            throw new Exception($"Error listing containers: {ex.Message}", ex);
    85→        }
    86→
    87→        return containers;
