     6→public class CommandGroup(string name, string description)
     7→{
     8→    public string Name { get; } = name;
     9→    public string Description { get; } = description;
    10→    public List<CommandGroup> SubGroup { get; } = [];
    11→    public Dictionary<string, IBaseCommand> Commands { get; } = [];
    12→    public Command Command { get; } = new Command(name, description);
    13→
    14→    public void AddCommand(string path, IBaseCommand command)
    15→    {
    16→        // Split on first dot to get group and remaining path
    17→        var parts = path.Split(['.'], 2);
    18→
    19→        if (parts.Length == 1)
    20→        {
    21→            // This is a direct command for this group
    22→            Commands[path] = command;
    23→        }
    24→        else
    25→        {
    26→            // Find or create the subgroup
    27→            var subGroup = SubGroup.FirstOrDefault(g => g.Name == parts[0]) ??
    28→                throw new InvalidOperationException($"Subgroup {parts[0]} not found. Group must be registered before commands.");
    29→
    30→            // Recursively add command to subgroup
    31→            subGroup.AddCommand(parts[1], command);
    32→        }
    33→    }
