namespace AzureMcp.TestsTmp;

public class DirectoryCreateCommandTests_tmp
{
    [Fact]
    public async Task ExecuteAsync_WithValidParameters_CallsServiceAndReturns200()
    {
        var storageService = Substitute.For<IStorageService>();
        var logger = Substitute.For<ILogger<DirectoryCreateCommand>>();
        var services = new ServiceCollection().AddSingleton(storageService).BuildServiceProvider();

        var command = new DirectoryCreateCommand(logger);
        var parser = new Parser(command.GetCommand());
        var context = new CommandContext(services);

        var args = parser.Parse([
            "--account-name", "acct",
            "--file-system-name", "fs",
            "--directory-path", "dir1/dir2",
            "--subscription", "sub"
        ]);

        var response = await command.ExecuteAsync(context, args);

        Assert.Equal(200, response.Status);
        await storageService.Received(1).CreateDataLakeDirectory(
            "acct", "fs", "dir1/dir2", "sub", Arg.Any<string?>(), Arg.Any<RetryPolicyOptions?>());
    }

    [Theory]
    [InlineData("--file-system-name fs --directory-path dir --subscription sub", false)] // missing account
    [InlineData("--account-name acct --directory-path dir --subscription sub", false)] // missing file-system
    [InlineData("--account-name acct --file-system-name fs --subscription sub", false)] // missing directory
    [InlineData("--account-name acct --file-system-name fs --directory-path dir", false)] // missing subscription
    [InlineData("--account-name acct --file-system-name fs --directory-path dir --subscription sub", true)]
    public async Task ExecuteAsync_ValidatesRequiredParameters(string args, bool shouldSucceed)
    {
        var storageService = Substitute.For<IStorageService>();
        var logger = Substitute.For<ILogger<DirectoryCreateCommand>>();
        var services = new ServiceCollection().AddSingleton(storageService).BuildServiceProvider();

        if (shouldSucceed)
        {
            storageService.CreateDataLakeDirectory(
                Arg.Any<string>(), Arg.Any<string>(), Arg.Any<string>(), Arg.Any<string>(),
                Arg.Any<string?>(), Arg.Any<RetryPolicyOptions?>()).Returns(Task.CompletedTask);
        }

        var command = new DirectoryCreateCommand(logger);
        var parser = new Parser(command.GetCommand());
        var context = new CommandContext(services);

        var parseResult = parser.Parse(args.Split(' '));
        var response = await command.ExecuteAsync(context, parseResult);

        Assert.Equal(shouldSucceed ? 200 : 400, response.Status);
    }

    [Fact]
    public async Task ExecuteAsync_HandlesException()
    {
        var storageService = Substitute.For<IStorageService>();
        var logger = Substitute.For<ILogger<DirectoryCreateCommand>>();
        var services = new ServiceCollection().AddSingleton(storageService).BuildServiceProvider();

        storageService.CreateDataLakeDirectory(
            Arg.Any<string>(), Arg.Any<string>(), Arg.Any<string>(), Arg.Any<string>(),
            Arg.Any<string?>(), Arg.Any<RetryPolicyOptions?>()).ThrowsAsync(new Exception("boom"));

        var command = new DirectoryCreateCommand(logger);
        var parser = new Parser(command.GetCommand());
        var context = new CommandContext(services);

        var args = parser.Parse([
            "--account-name", "acct",
            "--file-system-name", "fs",
            "--directory-path", "dir",
            "--subscription", "sub"
        ]);

        var response = await command.ExecuteAsync(context, args);

        Assert.Equal(500, response.Status);
        Assert.Contains("boom", response.Message);
    }
}

