using AzureMcp.Services.Telemetry;
using Microsoft.Extensions.Logging;

namespace AzureMcp.Areas.Storage.Commands.DataLake.Directory;

public sealed class DirectoryCreateCommand(ILogger<DirectoryCreateCommand> logger) : BaseDirectoryCommand<CreateDirectoryOptions>
{
    private const string CommandTitle = "Create Data Lake Directory";
    private readonly ILogger<DirectoryCreateCommand> _logger = logger;

    public override string Name => "create";

    public override string Description =>
        """
        Create a directory in an Azure Data Lake Storage Gen2 file system.
        This command creates the specified directory path within the given file system.

        Required options:
        - --account-name: The storage account name.
        - --file-system-name: The Data Lake file system name.
        - --directory-path: The directory path to create.
        - --subscription: The subscription ID or subscription name.
        """;

    public override string Title => CommandTitle;

    [McpServerTool(Destructive = true, ReadOnly = false, Title = CommandTitle)]
    public override async Task<CommandResponse> ExecuteAsync(CommandContext context, ParseResult parseResult)
    {
        var options = BindOptions(parseResult);

        try
        {
            if (!Validate(parseResult.CommandResult, context.Response).IsValid)
            {
                return context.Response;
            }

            context.Activity?.WithSubscriptionTag(options);

            var storageService = context.GetService<IStorageService>();
            await storageService.CreateDataLakeDirectory(
                options.Account!,
                options.FileSystem!,
                options.DirectoryPath!,
                options.Subscription!,
                options.Tenant,
                options.RetryPolicy);

            context.Response.Results = ResponseResult.Create(
                new DirectoryCreateCommandResult(options.DirectoryPath!),
                StorageJsonContext.Default.DirectoryCreateCommandResult);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex,
                "Error creating Data Lake directory. Account: {Account}, FileSystem: {FileSystem}, DirectoryPath: {DirectoryPath}.",
                options.Account, options.FileSystem, options.DirectoryPath);
            HandleException(context.Response, ex);
        }

        return context.Response;
    }

    internal record DirectoryCreateCommandResult(string DirectoryPath);
}
